import React, { useState, useEffect } from 'react';
import { useUser } from '../context/UserContext';
import './SubscriptionModal.css';

export function SubscriptionModal({ isOpen, onClose }) {
  const { purchaseSubscription } = useUser();
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState(null);

  useEffect(() => {
    if (isOpen) {
      setPlans([
        {
          id: 'monthly',
          name: 'Monthly',
          price: 99,
          duration: '1 month',
          features: ['Unlimited prompts', 'Priority support', 'Cancel anytime'],
          popular: false
        },
        {
          id: 'quarterly',
          name: '6 Months',
          price: 299,
          duration: '6 months',
          features: ['Unlimited prompts', 'Priority support', 'Save 25%', 'Cancel anytime'],
          popular: true
        },
        {
          id: 'yearly',
          name: 'Yearly',
          price: 499,
          duration: '1 year',
          features: ['Unlimited prompts', 'Priority support', 'Save 43%', 'Cancel anytime'],
          popular: false
        }
      ]);
    }
  }, [isOpen]);

  const handlePurchase = async (planId) => {
    setLoading(true);
    setSelectedPlan(planId);
    try {
      const result = await purchaseSubscription(planId);
      if (result.success) {
        alert(`✅ Successfully subscribed to ${result.data.message}`);
        onClose();
      }
    } catch (error) {
      alert(`❌ Error: ${error}`);
    } finally {
      setLoading(false);
      setSelectedPlan(null);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="subscription-modal-overlay" onClick={onClose}>
      <div className="subscription-modal" onClick={e => e.stopPropagation()}>
        <button className="close-btn" onClick={onClose}>×</button>

        <div className="modal-header">
          <h2>🚀 Unlock Unlimited Prompts</h2>
          <p>You've used your free prompts. Upgrade to continue exploring!</p>
        </div>

        <div className="plans-container">
          {plans.map(plan => (
            <div 
              key={plan.id} 
              className={`plan-card ${plan.popular ? 'popular' : ''}`}
            >
              {plan.popular && <div className="popular-badge">Most Popular</div>}
              
              <h3>{plan.name}</h3>
              <div className="price">
                <span className="amount">${plan.price}</span>
                <span className="period">/{plan.duration}</span>
              </div>

              <ul className="features">
                {plan.features.map((feature, idx) => (
                  <li key={idx}>
                    <span className="checkmark">✓</span>
                    {feature}
                  </li>
                ))}
              </ul>

              <button
                className={`subscribe-btn ${selectedPlan === plan.id ? 'loading' : ''}`}
                onClick={() => handlePurchase(plan.id)}
                disabled={loading}
              >
                {loading && selectedPlan === plan.id 
                  ? 'Processing...' 
                  : `Subscribe - $${plan.price}`
                }
              </button>
            </div>
          ))}
        </div>

        <div className="modal-footer">
          <p>💳 Secure payment powered by Stripe</p>
          <p className="note">No credit card required for free trial</p>
        </div>
      </div>
    </div>
  );
}

export default SubscriptionModal;
